def categorize_agencies(agencies):
    # Known examples for demonstration
    by_congress = ['TVA', 'NIRA-related programs']
    by_executive_order = ['WPA', 'Office of Censorship', 'FSA', 'SEC']

    # Initialize dictionaries
    categorized = {
        'established_by_congress': [],
        'established_by_executive_order': []
    }

    # Categorize each agency
    for agency in agencies:
        if agency in by_congress:
            categorized['established_by_congress'].append(agency)
        elif agency in by_executive_order:
            categorized['established_by_executive_order'].append(agency)
        else:
            categorized['established_by_executive_order'].append(agency)  # Default assumption

    return categorized

# Example usage:
agencies = ['TVA', 'WPA', 'SEC', 'PWA', 'CCC']
print(categorize_agencies(agencies))
# Output: {'established_by_congress': ['TVA'], 'established_by_executive_order': ['WPA', 'SEC', 'PWA', 'CCC']}

Note: This function uses a simplified lookup. In practice, a more comprehensive dataset of agencies and their establishment methods would be required for accurate classification.
